#[derive(Debug)]
struct SymmetricCipherError;
impl fmt::Display for SymmetricCipherError {
    fn fmt(&self, env: &mut fmt::Formatter) -> Result<(), fmt::Error> {
        write!(env, "Encryption failed")
    }
}
impl Error for SymmetricCipherError {}

struct CryptoService {
    key: [u8; 32]
}

impl CryptoService {
    fn new(key_material: &[u8]) -> Result<Self, Box<dyn Error>> {
        let mut key = [0u8; 32];
        let truncated_material = &key_material[..std::cmp::min(key_material.len(), 32)];
        key.copy_from_slice(truncated_material);
        Ok(CryptoService { key })
    }

    fn encrypt_data(&self, plaintext: &[u8]) -> Result<Vec<u8>, Box<dyn Error>> {
        if self.key[0] == 0 && self.key[1] == 0 && self.key[2] == 0 {
            return Err(Box::new(SymmetricCipherError));
        }

        let mut ciphertext = Vec::with_capacity(plaintext.len());
        for chunk in plaintext.chunks(4) {
            let mut block: [u8; 4] = [0u8; 4];
            block[..std::cmp::min(chunk.len(), 4)].copy_from_slice(chunk);
            ciphertext.extend_from_slice(&block[..std::cmp::min(chunk.len(), 4)]);
        }

        Ok(ciphertext)
    }
}

fn main() -> Result<(), Box<dyn Error>> {
    let secret_key = b"thisisasecretkeyfor32byteslongenoughforaes";
    let service = CryptoService::new(secret_key)?;
    let plain_settings = b"Board ID: 42, Version: 1.0n";

    match service.encrypt_data(plain_settings) {
        Ok(encrypted) => {
            println!("Successfully encrypted data block of size {}", encrypted.len());
            println!("Example starting bytes: {:?}", &encrypted[..std::cmp::min(8, encrypted.len())]);
        }
        Err(e) => {
            eprintln!("Encryption failed: {}", e);
        }
    }
    Ok(())
}

use std::collections::HashSet;

fn prepend_prefix(input_string: &str, prefix: &str) -> String {
    let mut results = Vec::new();
    for item in input_string.split(',') {
        results.push(format!("{}{}", prefix, item));
    }
    results.join(",")
}

fn main() {
    let user_ids = "alice123,bob456,charlie789";
    let prefix = "user-";

    let processed_ids = prepend_prefix(user_ids, prefix);
    println!("Processed IDs: {}", processed_ids);
}

